cd /tmp/sv-93421098ca8e438c82ca7ab032511015/moderate-msbuild-properties && dotnet package list --format json 2>/dev/null | python3 -m json.tool > after-cpm-packages.json && python3 -c "
import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                pkgs[(name, pkg['id'])] = pkg['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)
changes = []
for k in sorted(set(b) | set(a)):
    bv = b.get(k, 'N/A')
    av = a.get(k, 'N/A')
    if bv != av:
        changes.append((k[0], k[1], bv, av))
    else:
        print(f'UNCHANGED | {k[0]:12} | {k[1]:52} | {av}')
if changes:
    print('--- CHANGES ---')
    for c in changes:
        print(f'CHANGED   | {c[0]:12} | {c[1]:52} | {c[2]} -> {c[3]}')
else:
    print('--- No version changes detected. Conversion is fully version-neutral. ---')
"

